// src/components/ListingList.js
import React from "react";
import ListingCard from "./ListingCard";

function ListingList({ listings, onSelect }) {
  return (
    <div>
      {listings.map((listing) => (
        <ListingCard
          key={listing.id}
          listing={listing}
          onSelect={onSelect}
        />
      ))}
    </div>
  );
}

export default ListingList;
